mapper.select:
SELECT pr.*, u.id AS u_id, u.username AS u_username, u.nickname AS u_nickname, u.avatar AS u_avatar FROM product_review pr LEFT JOIN user u ON pr.user_id = u.id AND u.is_deleted = 0 WHERE pr.product_id = #{productId} AND pr.status = 1 AND pr.is_deleted = 0
AND pr.rating = #{rating}
ORDER BY pr.create_time DESC

SELECT pr.*, u.id AS u_id, u.username AS u_username, u.nickname AS u_nickname, u.avatar AS u_avatar FROM product_review pr LEFT JOIN user u ON pr.user_id = u.id AND u.is_deleted = 0 WHERE pr.is_deleted = 0
AND ( pr.content LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') )
AND pr.status = #{status}
AND pr.rating = #{rating}
AND pr.product_id = #{productId}
AND pr.user_id = #{userId}
ORDER BY pr.create_time DESC
